export const tbActivities: Activity[] = [
  {"id":"tb-all-aboard-shrinking-tarp","title":"All Aboard (Shrinking Island)","altNames":["Shrinking Island","Toxic Tarp","Magic Carpet"],"type":"Game","place":"Both","ageMin":9,"ageMax":18,"durationMin":30,"groupMin":6,"groupMax":16,"energy":2,"prep":"Low","blurb":"The whole team must fit onto a tarp 'island' that keeps folding smaller until they're packed shoulder to shoulder solving how to stand together.","materials":["1 tarp, picnic blanket, or bedsheet per team (about 6x6 ft)","Masking tape (optional, to mark a square on pavement instead of a tarp)","1 timer or phone"],"materialTags":["Masking tape"],"steps":["Spread one tarp flat on the ground and gather a team of 6 to 12 campers around it.","Challenge them: get every teammate's feet fully onto the tarp at the same time, no part touching the ground.","Once they succeed, have them step off and fold the tarp in half so it's noticeably smaller.","Repeat the challenge on the smaller surface, letting them strategize about who stands where and who holds whom.","Keep folding the tarp after each success until the team genuinely cannot fit, then declare their best round.","Debrief: ask how their plan changed as space shrank and who suggested the winning idea."],"notes":"Groups of 8 to 10 hit the sweet spot; pair a confident planner with quieter campers so everyone gets a voice. Expect the first 'impossible' fold to spark the best teamwork. To scale UP, ban talking on the final two folds, or require they hold the position for a full 10-second count.","safety":"Allow piggyback holds and linked arms but NO climbing onto shoulders or stacking bodies; on pavement use a taped square instead of a slick tarp so nobody slides, and keep the surface clear of rocks.","ages":["g46","g79","g1012"],"rating":0,"media":[{"title":"Video demos: All Aboard shrinking tarp","url":"https://www.youtube.com/results?search_query=all+aboard+shrinking+tarp+team+building+challenge"}],"links":[{"label":"More ideas: All Aboard shrinking island","url":"https://www.google.com/search?q=all+aboard+shrinking+tarp+team+building+challenge"}],"variations":["Silent Folds: forbid all talking on the last two rounds so the team must coordinate by gesture only (harder, for g79-g1012).","Hold the Count: a fit only counts if they stay fully aboard for a steady 10-second count.","Flip Side: each round they must flip the tarp over while everyone stays aboard before the fold counts.","Two-Island Merge: two teams each shrink their own tarp, then must combine onto one tarp for a finale."],"subsets":[["Use a taped square on pavement if you have no tarp"],[],[],["Encourage them to assign 'edge holders' and 'center anchors'"],[],[]]},
  {"id":"tb-helium-stick","title":"Helium Stick","altNames":["Helium Pole","Floating Stick","The Levitating Rod"],"type":"Game","place":"Both","ageMin":9,"ageMax":18,"durationMin":15,"groupMin":6,"groupMax":14,"energy":1,"prep":"Low","blurb":"A lightweight pole seems to magically float UP as the whole team tries to lower it, because everyone's fingers keep pushing without meaning to.","materials":["1 long lightweight rod per team (a cardboard tube, taped paper-towel tubes end to end, or a straw bundle, about 4-6 ft)","Masking tape to join tubes"],"materialTags":["Cardboard","Masking tape"],"steps":["Tape paper-towel tubes end to end to make one straight, very light pole about 5 feet long.","Line the team up in two facing rows and have each camper extend BOTH index fingers out at chest height.","Rest the pole across everyone's outstretched index fingers; every finger must stay touching it the whole time.","Give one rule: the goal is to lower the pole all the way to the ground together, and no finger may ever lose contact.","Step back and watch, because the pole will mysteriously rise instead of fall as fingers press up to stay in contact.","When they finally calm their movements and lower it, debrief why the 'helium' happened and what fixed it."],"notes":"Works with 8 to 12 campers; the lighter the pole the stronger the rising illusion. Resist explaining the trick early, the confusion IS the lesson in coordination. To scale UP for older grades, have them lower it with eyes closed, or assign one quiet 'caller' who must verbally pace the descent.","safety":"Keep the pole low and horizontal so nobody jabs an eye if it slips, and remind campers to point fingers down-and-out rather than toward each other's faces.","ages":["g46","g79","g1012"],"rating":0,"media":[{"title":"Video demos: Helium Stick","url":"https://www.youtube.com/results?search_query=helium+stick+team+building+game+instructions"}],"links":[{"label":"More ideas: Helium Stick","url":"https://www.google.com/search?q=helium+stick+team+building+activity"}],"variations":["Eyes Closed: the entire team lowers the pole with eyes shut, relying only on touch and one verbal caller (harder, for g79-g1012).","Knuckle Mode: rest the pole on the backs of flat knuckles instead of fingertips to raise the difficulty.","Two-Pole Tandem: balance two poles at once across two interlocked rows.","Reverse Goal: start the pole on the ground and have them raise it overhead together without gripping."],"subsets":[["Keep it under a pound so it rises easily"],[],["The pole rests ON TOP of fingers, campers may not curl fingers over it"],[],[],["Reveal that upward finger pressure adds up across the whole team"]]},
  {"id":"tb-group-juggle-name-toss","title":"Group Juggle","altNames":["Name Toss","Web of Balls","Pattern Juggle"],"type":"Game","place":"Both","ageMin":9,"ageMax":18,"durationMin":15,"groupMin":8,"groupMax":20,"energy":2,"prep":"Low","blurb":"The circle builds one fixed throwing pattern, then keeps adding balls until the whole team is juggling a dozen tosses at once.","materials":["6-10 soft tossable objects (playground balls, balled-up paper-towel wads, or sock balls)","Open circle space"],"materialTags":["Playground balls"],"steps":["Stand the group in a circle and have everyone raise a hand; you'll establish one repeating throw order.","Start with one ball: throw to someone across the circle, who throws to a new person, until everyone has caught it exactly once and it returns to you.","Run that same pattern two or three times so every camper memorizes who they receive from and who they throw to.","Now feed a second ball into the same pattern a few seconds behind the first, then a third, then a fourth.","Keep adding balls until the pattern breaks down in glorious chaos, then count the most balls they kept alive.","Reset and challenge them to beat their record, talking about eye contact and calling names before each throw."],"notes":"Ideal with 10 to 16 campers; fewer than 8 makes the pattern too short to feel like juggling. Insist they call the catcher's name before every throw, it doubles as a name game on day one. To scale UP, reverse the pattern mid-round on your whistle, or add a 'fast lane' ball that must travel the pattern backward.","safety":"Use only soft, lightweight objects and coach underhand tosses aimed at the chest, never the head; clear the circle of trip hazards since eyes are up and watching the air.","ages":["g46","g79","g1012"],"rating":0,"media":[{"title":"Video demos: Group Juggle name toss","url":"https://www.youtube.com/results?search_query=group+juggle+name+toss+team+building+circle+game"}],"links":[{"label":"More ideas: Group Juggle","url":"https://www.google.com/search?q=group+juggle+pattern+team+building+game"}],"variations":["Reverse on Whistle: at a random whistle the entire pattern must instantly run backwards (harder, for g79-g1012).","Speed Round: time how fast one ball can complete the full pattern cleanly.","Mixed Objects: feed in objects of different weights and shapes so each demands a different throw.","Two Patterns: run one ball clockwise-named while a second ball follows a totally separate order at the same time."],"subsets":[[],["Everyone catches the ball exactly once, no repeats"],["Each camper points to confirm their thrower and their catcher"],["Wait a few seconds between launching each new ball"],[],["Calling names out loud is the single biggest fix for drops"]]},
  {"id":"tb-blindfold-minefield","title":"Blindfold Minefield","altNames":["Minefield","Toxic Waste Walk","Trust Maze"],"type":"Game","place":"Both","ageMin":9,"ageMax":18,"durationMin":30,"groupMin":6,"groupMax":20,"energy":2,"prep":"Medium","blurb":"One blindfolded camper crosses a field of 'mines' guided only by a partner's voice, building real trust one careful step at a time.","materials":["Blindfolds (bandanas or paper towels folded and tied), 1 per pair","20-30 'mines': cones, playground balls, balloons, paper cups, foam sheets","Cones to mark a start and finish line"],"materialTags":["Cones","Balloons","Playground balls","Paper plates/cups","Foam sheets"],"steps":["Mark a rectangular field with a start and finish line, then scatter 20-30 soft 'mines' randomly across it.","Pair up campers; one wears a blindfold and stands at the start, the partner stays OUTSIDE the field at the edge.","On go, the outside partner uses ONLY voice directions to steer their blindfolded teammate across without touching any mine.","If the walker bumps a mine, they restart from the beginning, so the guide must learn clearer, calmer instructions.","When a pair crosses cleanly, they swap roles and run it again so both campers lead and follow.","Debrief which directions worked best and how trust felt different as guide versus walker."],"notes":"Pairs work for any group size; run several lanes at once to keep everyone active. The teaching gold is in the debrief about clear communication and trust. To scale UP for older grades, forbid using left/right (forcing invented codes), or have one guide steer two blindfolded walkers at once.","safety":"Walkers must shuffle slowly with hands gently up at chest height, and you should station yourself in the field as a spotter to catch wanderers before they trip; never use hard or sharp objects as mines.","ages":["g46","g79","g1012"],"rating":0,"media":[{"title":"Video demos: Blindfold Minefield","url":"https://www.youtube.com/results?search_query=blindfold+minefield+team+building+trust+game"}],"links":[{"label":"More ideas: Blindfold Minefield","url":"https://www.google.com/search?q=blindfold+minefield+team+building+communication+game"}],"variations":["No Directions Words: guides may not say left, right, forward, or back and must invent a code with their walker first (harder, for g79-g1012).","Two Walkers: one guide steers two blindfolded teammates through the field simultaneously.","Noisy Field: run several pairs at once so each guide must make their voice cut through the crowd.","Carry the Cargo: the walker must also balance a cup of water across the field without spilling."],"subsets":[["Space mines so a careful path exists but isn't obvious"],["Check blindfolds actually block vision but aren't too tight"],["Guides may not touch the walker, voice only"],[],[],[]]},
  {"id":"tb-trust-circle-lean","title":"Trust Circle","altNames":["Circle of Trust","Sway Pod","Willow in the Wind"],"type":"Game","place":"Both","ageMin":9,"ageMax":15,"durationMin":15,"groupMin":7,"groupMax":12,"energy":1,"prep":"None","blurb":"One camper stands stiff in the center and gently sways into the supporting hands of a tight, trustworthy circle.","materials":["No supplies needed (soft grass strongly preferred)"],"materialTags":["Cones"],"steps":["Form a tight circle of 7 to 10 campers shoulder to shoulder with one volunteer standing in the exact center.","Teach the support stance: feet staggered front-and-back, knees soft, arms up with palms forward at chest height, ready to catch.","The center camper crosses their arms over their chest, stiffens like a board, and keeps their feet planted together.","On a clear 'ready, lean' call-and-response, the center camper tips gently in any direction into waiting hands.","The circle softly receives and passes them around, never letting them fall and never shoving them hard.","After a turn, swap the center camper and repeat, then debrief how it felt to fully trust the group."],"notes":"Keep circles small and snug (7 to 10) so supporters are always within arm's reach. Only campers who genuinely want a turn in the center should take one, never pressure anyone. This is a calmer, trust-deep activity; for g79 you can slightly widen the lean angle, but keep it gentle and well-spotted.","safety":"The center camper must stay stiff with feet planted and never jump or flop; supporters keep one foot back and catch with hands at chest level only, with you spotting directly behind the leaner the whole time, and skip this entirely on hard pavement.","ages":["g46","g79"],"rating":0,"media":[{"title":"Video demos: Trust Circle lean","url":"https://www.youtube.com/results?search_query=trust+circle+team+building+willow+in+the+wind+activity"}],"links":[{"label":"More ideas: Trust Circle","url":"https://www.google.com/search?q=trust+circle+willow+in+the+wind+team+building"}],"variations":["Eyes Closed Circle: the supporters keep their eyes closed and rely only on touch and the caller's pacing (for older, well-practiced g79 only).","Name Pass: supporters say the center camper's name as they receive the lean to build a welcoming feel.","Tighten and Loosen: slowly widen the circle a half step to gently increase the trust required.","Partner Sway: scale down to pairs facing each other for a lower-commitment first try."],"subsets":[[],["Demonstrate the catch stance yourself before any camper goes in"],["Stiff body and planted feet are non-negotiable"],["Use a verbal ready-check so the circle is set before any lean"],[],[]]},
  {"id":"tb-tower-build-challenge","title":"Tallest Tower Challenge","altNames":["Tower Build","Build the Tallest","Skyscraper Showdown"],"type":"Game","place":"Both","ageMin":9,"ageMax":18,"durationMin":45,"groupMin":6,"groupMax":24,"energy":2,"prep":"Medium","blurb":"Teams race the clock to build the tallest free-standing tower from a shared pile of cardboard, cups, and tape, and it must stand on its own at the buzzer.","materials":["Per team: 1 stack of paper/cardboard scraps, 20 paper cups, 20 straws, 1 roll masking tape, scissors","1 tape measure or yardstick","1 timer"],"materialTags":["Cardboard","Paper plates/cups","Straws","Masking tape","Scissors","Paper"],"steps":["Split campers into teams of 4 to 6 and give each team an identical kit of cups, straws, cardboard, and one roll of tape.","Announce the rules: build the tallest tower you can in 20 minutes, and it must stand free for a full 10-second count.","Give teams 3 minutes of hands-off planning time to sketch a design and divide jobs before they touch materials.","Start the clock and let teams build, reminding them every 5 minutes how much time remains.","At the buzzer, every team steps back, hands off, and you measure each tower that survives the 10-second stand.","Crown the tallest standing tower, then debrief which designs were stable and how teams used their planning time."],"notes":"Teams of 4 to 6 keep everyone hands-on; identical kits make it fair and competitive. The planning minutes are where leadership emerges, so protect them. To scale UP for g79-g1012, cap the tape (e.g. 1 arm's length only), ban the cardboard base, or add a rule that the top must hold a balanced playground ball.","safety":"Remind campers to cut straws and cardboard with points aimed down at the table, and keep tall towers away from face level so a collapse can't poke an eye; clear the floor around each build station.","ages":["g46","g79","g1012"],"rating":0,"media":[{"title":"Video demos: Tallest Tower Challenge","url":"https://www.youtube.com/results?search_query=tallest+free+standing+tower+building+stem+challenge+kids"}],"links":[{"label":"Little Bins for Little Hands: summer camp activities","url":"https://littlebinsforlittlehands.com/summer-camp-activities/"},{"label":"More ideas: Tallest Tower Challenge","url":"https://www.google.com/search?q=tallest+tower+building+team+challenge+kids"}],"variations":["Limited Tape: each team gets only one arm's length of tape, forcing smarter joints (harder, for g79-g1012).","Load Test: the tower must hold a balanced playground ball at the very top to count.","Silent Build: the final 5 minutes are completed in total silence.","Earthquake Round: the finished tower must survive a gentle 5-second table shake."],"subsets":[["Pre-bag identical kits so setup is instant and fair"],["Free-standing means no leaning on walls, people, or furniture"],["No touching materials during planning, just designing and assigning roles"],[],["Measure from the floor to the highest point that's still standing"],[]]},
  {"id":"tb-junkyard-wars-build","title":"Junkyard Wars","altNames":["Junkyard Build Challenge","Scrap Build","Trash to Treasure Build"],"type":"Game","place":"Both","ageMin":9,"ageMax":18,"durationMin":60,"groupMin":6,"groupMax":24,"energy":2,"prep":"High","blurb":"Teams get an identical pile of camp 'junk' and a secret mission, then engineer a working contraption to beat every rival design.","materials":["Per team identical 'junk' pile: cardboard, paper cups, straws, paper plates, rubber bands, clothespins, string, tape, foam scraps","Scissors","1 challenge card per round (e.g. 'launch a paper ball farthest', 'carry an egg of crumpled paper across the room')","1 measuring tape"],"materialTags":["Cardboard","Paper plates/cups","Straws","Rubber bands","Yarn","Masking tape","Foam sheets","Scissors"],"steps":["Pre-sort identical 'junk' piles, one per team of 4 to 6, so every team starts with the exact same materials.","Reveal the mission card for the round, for example 'build a launcher that flings a paper ball the farthest'.","Give teams 5 minutes to plan, assign builder and tester roles, and agree on a design before building.","Run a 25-minute build window; teams may test and rebuild but must use only their assigned pile and tape.","Line teams up for the showdown and run each contraption through the same fair test, recording results.","Award the winning build, then debrief what trade-offs each team made and what they'd redesign."],"notes":"Teams of 4 to 6 with identical kits keep it fair; the mission card sets the whole tone, so prep two or three options. Expect loud, messy iteration, that's the point. To scale UP for g79-g1012, add an engineering constraint (must include a moving part, may use no more than 6 pieces of tape) or run two mission rounds and total the scores.","safety":"Establish a clear 'test zone' so launchers and flingers are only fired downrange away from people, and require safety-scissor use with cuts directed away from hands; inspect any rubber-band-powered build before it's launched at full tension.","ages":["g46","g79","g1012"],"rating":0,"media":[{"title":"Video demos: Junkyard Wars build challenge","url":"https://www.youtube.com/results?search_query=junkyard+wars+build+challenge+kids+camp+stem"}],"links":[{"label":"CampMinder: 27 summer camp activities","url":"https://campminder.com/resources/27-summer-camp-activities-to-spice-up-the-summer-camp-atmosphere/"},{"label":"More ideas: Junkyard Wars build","url":"https://www.google.com/search?q=junkyard+wars+build+challenge+camp+stem"}],"variations":["Constraint Round: the build must include a moving part and use no more than six pieces of tape (harder, for g79-g1012).","Two-Mission Total: run two different challenge cards back to back and add the scores.","Mystery Materials: hold back one bonus material per team revealed only at the 10-minute mark.","Pitch It: teams get 30 seconds to 'sell' their design to a judge for bonus style points."],"subsets":[["Bag each pile ahead of time and count pieces so teams match exactly"],["Have a couple of backup mission cards ready in case one falls flat"],["Roles like lead builder, materials manager, and tester keep chaos productive"],[],["Run the identical test on every entry so results are comparable"],[]]},
  {"id":"tb-invention-challenge","title":"Invention Challenge","altNames":["Invent-a-Thon","Solve-It Build","Problem Solvers"],"type":"Game","place":"Both","ageMin":9,"ageMax":18,"durationMin":60,"groupMin":4,"groupMax":24,"energy":2,"prep":"Medium","blurb":"Teams draw a silly everyday problem and invent a prototype gadget from craft supplies to solve it, then pitch it like inventors.","materials":["Shared supply table: cardboard, paper, foam sheets, pipe cleaners, straws, cups, rubber bands, clothespins, tape, markers, scissors","1 'problem card' per team (e.g. 'a hat that keeps your snack dry', 'a device to pass a note across the cabin')","Paper for a quick design sketch"],"materialTags":["Cardboard","Paper","Foam sheets","Pipe cleaners","Straws","Paper plates/cups","Rubber bands","Masking tape","Markers","Scissors"],"steps":["Split into invention teams of 3 to 5 and have each team draw a goofy 'problem card' from a hat.","Give teams 5 minutes to brainstorm and sketch a solution on paper before grabbing any materials.","Open the shared supply table and let teams gather what their design needs, sharing fairly with other teams.","Run a 25-minute build window where teams construct a working (or convincingly demonstrable) prototype.","Have each team give a 1-minute pitch: name the invention, the problem it solves, and a quick demo.","Vote on awards by category (most creative, most likely to actually work, best pitch) so multiple teams win."],"notes":"Teams of 3 to 5 keep the brainstorm lively without anyone hiding. The sketch-first rule forces planning before the supply scramble. To scale UP for older grades, require the invention to incorporate a simple mechanism (a lever, a launcher, a pulley made of string), and add a strict materials budget they must 'buy' against.","safety":"Keep scissors and any rubber-band tension pointed away from faces during demos, and remind teams that pitches must mime risky actions rather than actually launch objects toward the audience.","ages":["g46","g79","g1012"],"rating":0,"media":[{"title":"Video demos: Invention Challenge for kids","url":"https://www.youtube.com/results?search_query=invention+challenge+for+kids+camp+maker+prototype"}],"links":[{"label":"CampMinder: 27 summer camp activities","url":"https://campminder.com/resources/27-summer-camp-activities-to-spice-up-the-summer-camp-atmosphere/"},{"label":"More ideas: Invention Challenge","url":"https://www.google.com/search?q=invention+challenge+for+kids+camp+maker+activity"}],"variations":["Working Mechanism Required: the invention must include a real lever, pulley, or launcher and pass a live demo (harder, for g79-g1012).","Materials Budget: each item has a 'price' and teams must invent within a set point budget.","Mash-Up Cards: each team draws two problem cards and must solve both with one device.","Shark Tank: a panel of counselors judges and 'invests' in the best pitch."],"subsets":[["Write a dozen playful problem cards ahead of time"],["Sketches don't need to be pretty, just a labeled plan"],["Set a norm that the supply table is shared, not hoarded"],[],["Coach a simple pitch format: name it, what it fixes, show it"],["Multiple award categories mean every team can place"]]},
  {"id":"tb-escape-puzzle-lite","title":"Camp Escape Challenge","altNames":["Escape Room Lite","Lockbox Puzzle Hunt","Crack the Code"],"type":"Game","place":"Both","ageMin":9,"ageMax":18,"durationMin":45,"groupMin":4,"groupMax":16,"energy":1,"prep":"High","blurb":"Teams race the clock to solve a chain of hidden paper puzzles, each answer unlocking the next clue until the final code is cracked.","materials":["Pre-made paper puzzle clues (riddles, ciphers, number puzzles), 4-6 per chain","Markers and paper for puzzle creation","Envelopes or folded cards to hide clues","Optional: a small box closed with a number-combination written on a taped paper lock","1 timer"],"materialTags":["Paper","Markers","Masking tape"],"steps":["Before camp, write a chain of 4 to 6 paper puzzles where solving each one reveals where to find the next clue.","Hide the clues around the room or area and brief the team on the story and the time limit.","Start the timer and let the team find and open the first clue together to begin the chain.","Each solved puzzle points to the next hidden clue, so the team must split up, share findings, and stay organized.","The final puzzle reveals a code that 'unlocks' the box or finish card to win the challenge.","Stop the clock when they finish and debrief how they divided tasks and which clue stumped them most."],"notes":"Teams of 4 to 6 are ideal so everyone can hold a clue; for bigger groups run two parallel identical chains as a race. The prep is front-loaded but reusable all summer. To scale UP for g79-g1012, layer in a simple substitution cipher or a multi-step math lock, and add red-herring clues that must be reasoned out.","safety":"Hide clues at reachable heights only, never anywhere campers must climb, stand on furniture, or reach into unseen gaps; keep the search area bounded and supervised so the hunt doesn't spill into unsafe spaces.","ages":["g46","g79","g1012"],"rating":0,"media":[{"title":"Video demos: Camp Escape Challenge","url":"https://www.youtube.com/results?search_query=diy+escape+room+for+kids+camp+puzzle+clues"}],"links":[{"label":"More ideas: Camp Escape Challenge","url":"https://www.google.com/search?q=diy+escape+room+puzzle+chain+for+kids+camp"}],"variations":["Cipher Lock: include a substitution-cipher puzzle and a multi-step math combination for the final lock (harder, for g79-g1012).","Red Herrings: plant decoy clues the team must reason past to avoid wasting time.","Relay Chains: two teams race identical chains side by side for fastest finish.","Build-Your-Own: advanced teams design a 3-clue chain for another team to solve."],"subsets":[["Test the chain yourself once so no clue is a dead end"],["Set a tight, fair time limit like 20-25 minutes"],[],["Encourage a 'clue board' where they lay solved clues out for everyone to see"],[],[]]},
  {"id":"tb-leadership-relay","title":"Leadership Relay","altNames":["Captain's Relay","Caller Relay","Follow-the-Leader Relay"],"type":"Game","place":"Both","ageMin":9,"ageMax":18,"durationMin":30,"groupMin":8,"groupMax":24,"energy":3,"prep":"Medium","blurb":"A rotating captain must call the plays as the team races through a multi-station relay, so everyone gets a turn leading under pressure.","materials":["Cones to mark stations and a finish line","Playground balls","Hula hoops","Balloons","Paper cups and straws for a quick station task","1 task card per station"],"materialTags":["Cones","Playground balls","Balloons","Paper plates/cups","Straws"],"steps":["Set up 4 to 5 stations in a loop, each with a quick team task (hoop pass, balloon keep-up, cup stack, ball carry).","Split into teams and have each team pick a rotating order of 'captains', one per station.","At each station the current captain alone may direct the team and decide how to complete the task fastest.","Teams move station to station, swapping the captain role each time so leadership rotates through everyone.","Finish when a team completes all stations correctly and crosses the line; mis-done tasks must be redone.","Debrief which leadership styles worked and how it felt to both lead and follow within one race."],"notes":"Teams of 5 to 8 ensure everyone gets a captain turn; keep station tasks short so the relay keeps moving. The rotating-captain rule is the whole point, enforce it. To scale UP for older grades, add a 'curveball' card the captain must adapt to mid-station, or require the captain to lead without using teammates' names.","safety":"Keep running lanes wide and one-directional to avoid head-on collisions, and station a counselor at any task involving balloons so popped pieces are cleared immediately and no one mouths a balloon.","ages":["g46","g79","g1012"],"rating":0,"media":[{"title":"Video demos: Leadership Relay","url":"https://www.youtube.com/results?search_query=leadership+relay+team+building+station+game+camp"}],"links":[{"label":"More ideas: Leadership Relay","url":"https://www.google.com/search?q=leadership+rotating+captain+relay+team+building+camp"}],"variations":["Curveball Cards: the captain draws a surprise rule change at their station and must adapt the team on the fly (harder, for g79-g1012).","No-Names Lead: the captain must direct without using any teammate's name, forcing clearer instructions.","Silent Station: one station must be completed with the captain giving gestures only.","Reverse Relay: the team runs the loop backwards on the second round with the same rotating captains."],"subsets":[["Keep each station task under a minute to finish"],["Post the captain rotation so swaps are automatic"],["Only the captain talks at their station, teammates execute"],[],[],[]]},
  {"id":"tb-floor-is-lava-crossing","title":"The Floor Is Lava Crossing","altNames":["Lava Crossing","Stepping Stones Challenge","River Crossing"],"type":"Game","place":"Both","ageMin":9,"ageMax":18,"durationMin":30,"groupMin":6,"groupMax":18,"energy":2,"prep":"Low","blurb":"The whole team must cross a 'lava' zone using only a few shared foam 'stepping stones' that vanish the instant no one is touching them.","materials":["Foam sheets or paper plates as 'stones', fewer than the number of campers (e.g. 4 stones for 6 campers)","Cones to mark the lava banks","Optional: sidewalk chalk to draw the lava zone on pavement"],"materialTags":["Foam sheets","Paper plates/cups","Cones","Sidewalk chalk"],"steps":["Mark two 'safe bank' lines with cones a good distance apart and call everything between them lava.","Hand the team a few foam 'stepping stones', always fewer than the number of campers crossing.","Explain the catch: a stone left untouched by any hand or foot instantly 'floats away' and you remove it.","The team must get every member from one bank to the other using only the stones, never touching the lava.","If a stone is lost or a foot touches lava, the whole team restarts from the first bank.","When everyone reaches the far bank, debrief how they protected stones and sequenced the crossing."],"notes":"Groups of 6 to 10 with 3 to 5 stones hit the right difficulty; too many stones makes it trivial. The 'untouched stone floats away' rule forces constant teamwork and a hand always on each stone. To scale UP for g79-g1012, remove one stone, ban talking, or require they also ferry a 'cargo' cup of water across unspilled.","safety":"Use foam or paper plates, not slick plastic, so stones don't skid out underfoot, and forbid leaping between stones, campers must step carefully; on pavement draw the lava with chalk rather than using anything that slides.","ages":["g46","g79","g1012"],"rating":0,"media":[{"title":"Video demos: Floor Is Lava crossing challenge","url":"https://www.youtube.com/results?search_query=floor+is+lava+stepping+stones+team+building+crossing+challenge"}],"links":[{"label":"More ideas: The Floor Is Lava crossing","url":"https://www.google.com/search?q=floor+is+lava+stepping+stones+team+building+challenge"}],"variations":["One Stone Short: remove a stone and forbid talking so the team coordinates by gesture only (harder, for g79-g1012).","Cargo Run: the team must also ferry a full cup of water across without spilling.","Two-Way Traffic: two teams cross from opposite banks and must pass each other mid-lava.","Timed Crossing: race two teams to see who crosses cleanly fastest."],"subsets":[["Make the gap challenging but crossable with the stones given"],["Hand out stones equal to campers minus two or three"],["A stone with nobody touching it is removed immediately, no warnings"],[],["A clean restart resets the whole team, not just the camper who slipped"],[]]},
  {"id":"tb-marshmallow-straw-tower","title":"Straw & Tape Spaghetti Tower","altNames":["Straw Tower Challenge","Spaghetti Tower","Marshmallow Tower (No-Food Version)"],"type":"Game","place":"Both","ageMin":9,"ageMax":18,"durationMin":30,"groupMin":4,"groupMax":24,"energy":1,"prep":"Low","blurb":"Small teams engineer the tallest free-standing tower from a fixed kit of straws and tape, topped by a single balloon 'marshmallow' that must stay put.","materials":["Per team: 20 straws, 1 yard of masking tape, scissors, 1 balloon (the 'marshmallow' that tops the tower)","1 tape measure","1 timer"],"materialTags":["Straws","Masking tape","Scissors","Balloons"],"steps":["Give each team of 3 to 4 an identical kit: 20 straws, exactly one yard of tape, scissors, and one balloon.","Set the goal: build the tallest free-standing tower in 18 minutes that can support the balloon on top.","Allow 2 minutes of planning before any straw is touched so the team agrees on a structure.","Start the clock; teams build, test, and reinforce, but may use only their assigned straws and tape.","At time, every team sets its balloon on top and steps back; the tower must hold it standing for a 10-second count.","Measure each standing tower with the balloon in place and crown the tallest, then debrief stable shapes like triangles."],"notes":"Teams of 3 to 4 keep everyone building; the fixed one-yard tape limit is what makes it an engineering puzzle. The balloon-on-top rule rewards stability, not just height. To scale UP for g79-g1012, cut the tape to half a yard, require the tower to also survive a gentle table shake, or set a minimum height the balloon must clear.","safety":"Have campers cut and bend straws with the ends pointed down at the table to avoid eye pokes, and remind them not to over-inflate balloons or hold them near faces; clear popped balloon scraps right away.","ages":["g46","g79","g1012"],"rating":0,"media":[{"title":"Video demos: straw and tape tower challenge","url":"https://www.youtube.com/results?search_query=straw+and+tape+tower+stem+challenge+marshmallow+tower+kids"}],"links":[{"label":"Little Bins for Little Hands: summer camp activities","url":"https://littlebinsforlittlehands.com/summer-camp-activities/"},{"label":"More ideas: Straw tower challenge","url":"https://www.google.com/search?q=straw+tape+marshmallow+tower+stem+challenge+kids"}],"variations":["Half-Tape Hard Mode: teams get only half a yard of tape and the tower must clear a minimum height (harder, for g79-g1012).","Earthquake Test: the finished tower must survive a gentle 5-second table shake with the balloon on top.","No-Cut Rule: straws may be bent and woven but never cut.","Bridge Pivot: same kit, but build the longest cantilever reaching out from a table edge instead of a tower."],"subsets":[["Pre-count straws and tear tape to exactly one yard per team for fairness"],["Free-standing means no taping to the table, floor, or wall"],["Coach them to plan a wide, triangular base"],[],["The balloon must rest on top, not be held, during the 10-second count"],["Point out that triangles are far more rigid than squares"]]},
];
